// ── Migration ───────────────────────────────────────────────────────────

async function migrate() {
  await mongoose.connect(MONGO_URI);
  console.log('Connected to MongoDB\n');

  const db = mongoose.connection.db;
  const postsCol = db.collection('posts');
  const papersCol = db.collection('paper');

  // Migrate posts
  let postUpdated = 0;
  let postSkipped = 0;
  for (const [id, topics] of Object.entries(POST_TOPICS)) {
    const oid = new mongoose.Types.ObjectId(id);
    const existing = await postsCol.findOne({ _id: oid }, { projection: { topics: 1, title: 1 } });
    if (!existing) {
      console.log(`  [SKIP] Post ${id} not found`);
      postSkipped++;
      continue;
    }
    if (existing.topics && existing.topics.length > 0) {
      console.log(`  [SKIP] Post "${existing.title}" already has topics: [${existing.topics.join(', ')}]`);
      postSkipped++;
      continue;
    }
    await postsCol.updateOne({ _id: oid }, { $set: { topics } });
    console.log(`  [OK]   Post "${existing.title}" → [${topics.join(', ')}]`);
    postUpdated++;
  }
  console.log(`\nPosts: ${postUpdated} updated, ${postSkipped} skipped\n`);

  // Migrate papers
  let paperUpdated = 0;
  let paperSkipped = 0;
  for (const [id, topics] of Object.entries(PAPER_TOPICS)) {
    const oid = new mongoose.Types.ObjectId(id);
    const existing = await papersCol.findOne({ _id: oid }, { projection: { topics: 1, title: 1 } });
    if (!existing) {
      console.log(`  [SKIP] Paper ${id} not found`);
      paperSkipped++;
      continue;
    }
    if (existing.topics && existing.topics.length > 0) {
      console.log(`  [SKIP] Paper "${existing.title}" already has topics: [${existing.topics.join(', ')}]`);
      paperSkipped++;
      continue;
    }
    await papersCol.updateOne({ _id: oid }, { $set: { topics } });
    console.log(`  [OK]   Paper "${existing.title}" → [${topics.join(', ')}]`);
    paperUpdated++;
  }
  console.log(`\nPapers: ${paperUpdated} updated, ${paperSkipped} skipped`);

  await mongoose.disconnect();
  console.log('\nDone');
}

migrate().catch((err) => {
  console.error('Migration failed:', err);
  process.exit(1);
});
